Iterating through and cleaning up projectiles using range-based loops and reference semantics:

```cpp
#include <vector>

struct AProjectile {
    float Speed = 10.0f;
    bool IsActive = true;
    void Update(float DeltaTime) {
        // Position changes...
    }
};

std::vector<AProjectile> Projectiles;

void UpdateActiveProjectiles(float DeltaTime) {
    // Use references to prevent copying objects!
    for (AProjectile& CurrentProjectile : Projectiles) {
        if (CurrentProjectile.IsActive) {
            CurrentProjectile.Update(DeltaTime);
        }
    }
}
```
